from pymongo import MongoClient

def find_user_by_email(email, db):
    """
    Find user(s) by their email address in MongoDB.
    
    Args:
        email (str): Email address to search for.
        db (MongoDB client): MongoDB database instance.
    
    Returns:
        list: List of dictionaries representing found users.
    """
    collection = db['users']
    return collection.find_one({'email': email})

